  Future<String> _uploadToS3(File image) async {
    final url = 'https://$bucketName.s3.$region.amazonaws.com/';
    final key = 'images/${Uuid().v4()}.jpg';
    
    final fileBytes = await image.readAsBytes();
    final contentType = 'image/jpeg';
    
    final date = DateTime.now().toUtc();
    final dateString = '${date.year}${date.month.toString().padLeft(2, '0')}${date.day.toString().padLeft(2, '0')}';
    
    final amzDate = '${dateString}T${date.hour.toString().padLeft(2, '0')}${date.minute.toString().padLeft(2, '0')}${date.second.toString().padLeft(2, '0')}Z';
    
    final canonicalRequest = '''
PUT
/$key
X-Amz-Date:$amzDate
X-Amz-Content-Sha256:${sha256.convert(fileBytes).toString()}
Host:$bucketName.s3.$region.amazonaws.com

x-amz-date:$amzDate
x-amz-content-sha256:${sha256.convert(fileBytes).toString()}
host:$bucketName.s3.$region.amazonaws.com
x-amz-date:$amzDate
'''.trim();
    
    final canonicalRequestHash = sha256.convert(canonicalRequest.codeUnits).toString();
    
    final stringToSign = '''
AWS4-HMAC-SHA256
$amzDate
$region/s3/aws4_request
$canonicalRequestHash
'''.trim();
    
    final signingKey = _getSigningKey(awsSecretKey, dateString, region, 's3');
    final signature = hmacSha256(signingKey, stringToSign).toString();
    
    final headers = {
      'Authorization': 'AWS4-HMAC-SHA256 Credential=$awsAccessKey/$dateString/$region/s3/aws4_request, SignedHeaders=host;x-amz-date;x-amz-content-sha256, Signature=$signature',
      'x-amz-date': amzDate,
      'x-amz-content-sha256': sha256.convert(fileBytes).toString(),
      'Content-Type': contentType,
    };
    
    final response = await http.put(
      Uri.parse('$url$key'),
      headers: headers,
      body: fileBytes,
    );
    
    if (response.statusCode == 200) {
      return '$url$key';
    } else {
      throw Exception('Upload failed: ${response.statusCode}');
    }
  }

  Future<String> _analyzeImageWithVision(String imageUrl) async {
    final url = 'https://vision.googleapis.com/v1/images:annotate?key=$googleApiKey';
    
    final request = {
      'requests': [
        {
          'image': {
            'source': {
              'imageUri': imageUrl,
            },
          },
          'features': [
            {
              'type': 'LABEL_DETECTION',
              'maxResults': 10,
            },
            {
              'type': 'FACE_DETECTION',
              'maxResults': 5,
            },
            {
              'type': 'TEXT_DETECTION',
              'maxResults': 5,
            },
          ],
        },
      ],
    };
    
    final response = await http.post(
      Uri.parse(url),
      headers: {'Content-Type': 'application/json'},
      body: jsonEncode(request),
    );
    
    if (response.statusCode == 200) {
      final result = jsonDecode(response.body);
      final labels = result['responses'][0]['labelAnnotations'];
      final faces = result['responses'][0]['faceAnnotations'];
      final text = result['responses'][0]['textAnnotations'];
      
      String analysis = '';
      
      if (labels != null) {
        analysis += 'Labels:\n';
        for (var label in labels.take(5)) {
          analysis += '${label['description']} (${(label['score'] * 100).toStringAsFixed(2)}%)\n';
        }
      }
      
      if (faces != null) {
        analysis += '\nFaces: ${faces.length}\n';
      }
      
      if (text != null && text.isNotEmpty) {
        analysis += '\nText Detected:\n${text[0]['description']}\n';
      }
      
      return analysis;
    } else {
      throw Exception('Vision API failed: ${response.statusCode}');
    }
  }

