  Uint8List _getSigningKey(String secretKey, String date, String region, String service) {
    final kDate = _hmacSha256('AWS4$secretKey'.codeUnits, date.codeUnits);
    final kRegion = _hmacSha256(kDate, region.codeUnits);
    final kService = _hmacSha256(kRegion, service.codeUnits);
    return _hmacSha256(kService, 'aws4_request'.codeUnits);
  }

  Uint8List _hmacSha256(Uint8List key, Uint8List data) {
    return Uint8List.fromList(sha256.convert(key + data).bytes);
  }

  Uint8List hmacSha256(Uint8List key, String data) {
    return Uint8List.fromList(sha256.convert(key + data.codeUnits).bytes);
